arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    $findings = gh api "/repos/$REPO/pulls/14/reviews" --jq '.[] | select(.body | test("Copilot.s findings")) | {id: .id, body: .body}' 2>$null
    if ($findings) {
        Write-Host "Found Copilot review:"
        Write-Host $findings
        break
    }
    Write-Host "[$ELAPSED s] No review yet, waiting $INTERVAL s..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}
if ($ELAPSED -ge $TIMEOUT) {
    Write-Host "TIMEOUT: Copilot review not posted within 10 minutes"
}

